# ║ Path(c4_proof(fn,), decorator that marks a function as a c⁴ proof builder) over Optional[Callable] ║
# ╠════════════════════════════════════════════════════════════╣
# ║ c4_proof : Optional[Callable] → Any                        ║
# ╠════════════════════════════════════════════════════════════╣
# ║ Trusted:                                                   ║
# ║   z3.Solver.check                                          ║
# ╠════════════════════════════════════════════════════════════╣
# ║ 🟢 KERNEL | library_axiom | Compiled: ✓ | 4377f9d590e7ec56  ║
# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.dsl.c4_proof","kind":"function","src_hash":"9fc21602c2675c16","in":{"base":"Optional[Callable]"},"out":{"base":"Any"},"spec":{"lhs":"c4_proof(fn,)","rhs":"decorator that marks a function as a c\u2074 proof builder","over":{"base":"Optional[Callable]"},"name":"c4_proof_correct"},"guarantee":"decorator that marks a function as a c\u2074 proof builder","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.dsl.c4_proof_correct","statement":"Path(c4_proof(x), decorator that marks a function as a c\u2074 proof builder)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"4377f9d590e7ec56"}
def c4_proof(
    fn: Optional[Callable] = None,
    *,
    lhs: Optional[OTerm] = None,
    rhs: Optional[OTerm] = None,
) -> Any:
    """Decorator that marks a function as a C⁴ proof builder.

    The decorated function receives a ProofBuilder as its first argument
    and should use it to construct the proof.

    Usage::

        @c4_proof(lhs=FACT_REC, rhs=FACT_ITER)
        def factorial_equiv(pb):
            base = pb.refl(lit(1))
            ih = pb.assume('ih', FACT_REC, FACT_ITER)
            step = pb.trans(
                pb.congr('*', pb.refl(var('n')), ih),
                pb.axiom('fold_spec', 'backward', FACT_ITER),
            )
            pb.by_induction(on='n', base=base, step=step)

    The decorator returns the ProofBuilder (not the function).
    Call ``.build()`` to get the ProofTerm, ``.verify()`` to check it.
    """
    def wrapper(f: Callable) -> ProofBuilder:
        pb = ProofBuilder(lhs=lhs, rhs=rhs)
        f(pb)
        pb._doc = f.__doc__ or ''
        return pb

    if fn is not None:
        return wrapper(fn)
    return wrapper


